command.text:
        &GetUnitCode;
        &CommandWhenBalanceBeforeDelete;

if exists(select 1 from @@table where loai_tt = 1 and left(stt_rec_tt, 10) = left(@stt_rec, 10)) begin
  select @$deleteConflict as message
  return
end

script.text:
      /* <flatten type="Javascript"> */
function activeForm(f) {
  f.$a = {t_tt: '[t_tt]:=[t_tt_nt]*[ty_gia]', t_cl_nt: 't_cl_nt:=[t_tt_nt0] - [t_tt_qd0]'};
  f._controlFocus = f.getItem('ngay_ct');
  f.add_onResponseComplete(on$Form$ResponseComplete);
  setFormDefaultValue(f);
  f.executeExpression([f.$a.t_cl_nt]);
}
function closeForm(f) {try {f.remove_onResponseComplete(on$Form$ResponseComplete);} catch (ex) {}}
function setFormDefaultValue(f) {
  if (f._action == 'New') {
    f.getItem('ma_dvcs').value = f._unitCode;
    f.getItem('ten_dvcs%l').value = f._unitName;
  }
  if ($func.trim(f.getItemValue('ma_nt')) == '') {
    f.setItemValue('ma_nt', f._baseCurrency);
    f.getItem('ten_nt%l').value = f._baseCurrencyName;
  }
  onChangeCurrency(f);
}
function onChangeCurrency(f) {
  if (!f._baseCurrencyFormat) f._baseCurrencyFormat = f.getItem('t_tt')._controlBehavior._format;
  if (!f._foreignCurrencyFormat) f._foreignCurrencyFormat = f.getItem('t_tt_nt')._controlBehavior._format;
  var format = f._baseCurrencyFormat, c = f.getItemValue('ma_nt').toUpperCase();
  var v = (c == '' || c == f._baseCurrency);
  if (!v) format = f._foreignCurrencyFormat;
  var a = 't_tt_nt0, t_tt_qd0, t_cl_nt'.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    o.field.DataFormatString = format;
    o._controlBehavior.set_format(format);
  }
  f.getItem('t_tt_nt').disabled = f.getItem('ty_gia').disabled = v;
  if (v) {
    f.setItemValue('t_tt_nt', 0);
    f.setItemValue('ty_gia', 1);
  }
}
function onChange$Form$ItemCustomer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Form$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'ma_nt':
      onChangeCurrency(f);
      setReferenceValue(f);
      setFocusWhenCurrencyChange(f);
      break;
    case 't_tt_nt':
      setForeignFieldItemValue(f);
      break;
    case 'ty_gia':
      setForeignFieldItemValue(f);
      f.live(f.getItem('t_tt'));
      break;
    case 't_tt':
      setReferenceValue(f);
      break;
    case 't_tt_qd0':
      f.executeExpression([f.$a.t_cl_nt]);
      setWriteOffValue(f);
      break;
    default:
      break;
  }
}
function on$Form$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Scattering':
      setFormDefaultValue(f);
      f.executeExpression([f.$a.t_cl_nt]);
      break;
    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ma_tt', result[2].Value, result[3].Value, true);
      break;
    default:
      break;
  }
}
function setReferenceValue(f) {
  var c = f.getItemValue('ma_nt').toUpperCase();
  if (c != '' && c != f._baseCurrency) f.setItemValue('t_tt_nt0', f.getItemValue('t_tt_nt'));
    else f.setItemValue('t_tt_nt0', f.getItemValue('t_tt'));
  f.executeExpression([f.$a.t_cl_nt]);
  setWriteOffValue(f);
}
function setWriteOffValue(f) {f.setItemValue('tat_toan', f.getItemValue('t_cl_nt') > 0 ? '0' : '1');}
function setForeignFieldItemValue(f) {
  f.executeExpression([f.$a.t_tt]);
  f.setItemValue('t_tt_nt0', f.getItemValue('t_tt_nt'));
  f.executeExpression([f.$a.t_cl_nt]);
  setWriteOffValue(f);
}
function setFocusWhenCurrencyChange(f) {
  var c = f.getItemValue('ma_nt').toUpperCase();
  var n = (c == '' || c == f._baseCurrency) ? 't_tt' : 't_tt_nt';
  var o = f.getItem(n);
  try {o.focus(); f.live(o);} catch (ex) {}
}
/* </flatten> */
